	public MainForm()
	{
		SplashScreenManager.ShowForm(this, typeof(SplashScreen1), useFadeIn: true, useFadeOut: true, throwExceptionIfAlreadyOpened: false);
		SplashScreenManager.Default.SendCommand(SplashScreen1.SplashScreenCommand.InitializeDataWareHouse, 0);
		Thread.Sleep(25);
		InitializeComponent();
		AlienAge.ArabicTheology.TheologyHelperClasses.Classes classes = new AlienAge.ArabicTheology.TheologyHelperClasses.Classes();
		classes.PopulateAllClassesToComboEn(new ComboBoxEdit[2] { cboClassTHEditor, cboClassTHRpt });
		AlienAge.CommonSettings.Classes.LoadComboWithClasses(new ComboBoxEdit[27]
		{
			cboClassCompetency, cboClassComb, cboClassNewCurMarksheet, cbo_Class, cboClassRanking, cboClassStaticA, cboClassSum, cboClassPerf, cboClassExamP, cboClassMealCards,
			comboBoxEdit12, cboRptClass, cboMiniClass, cboMyClasses, cboClassID, cboClassStatic, cboAnnualClass, cboClassFB, cboClassWrite, cboRollCallClass,
			cboClassNCGM, cboClassIE, cboClassScoreboardRev, cboClassOldData, cboClassOtherReq, cboClassMarkAd, cboClassRankingNC
		});
		cbo_Class.Properties.Items.Insert(0, "All Classes");
		WorkingSemesters.GetSemesters(new ComboBoxEdit[30]
		{
			cboTermArrears, cboTermCompetency, cboTermComb, cboTermNewCurMarksheet, cboWorkingSemester, cboTermNC, comboBoxEdit9, cboSemRecoveryAnalysis, cboTermSum, cboPrePrimaryTerm,
			cboPrePrimaryTerm_2, cbo_semester, comboBoxEdit11, cboAnalysisSemester, cboSemesterStaticA, cboSemesterStatic, cboRptTerm, cboMiniTerm, cboTerm, cboTermWrite,
			cboTermAttendance, cboTermWaiver, cboTermNCGM, cboTermIE, cboTermOtherReq, cboTermTHEditor, cboTermTHRpt, cboTermMarkAd, cboTermRankingNC, cboTermAnaAL
		});
		cboTermTHRpt.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermTHEditor.SelectedItem = WorkingSemesters.GetWorkingSemester();
		txtTermOldData.Text = WorkingSemesters.GetWorkingSemester();
		cboTermIE.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermNCGM.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermWaiver.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboSemRecoveryAnalysis.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermCompetency.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cbo_semester.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboPrePrimaryTerm.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboPrePrimaryTerm_2.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboMiniTerm.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermNC.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermNewCurMarksheet.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermWrite.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermAttendance.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermComb.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermOtherReq.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermArrears.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermRankingNC.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermMarkAd.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTermAnaAL.SelectedItem = WorkingSemesters.GetWorkingSemester();
		AlienAge.CommonSettings.Classes.LoadComboWithClasses(cboPreprimaryClass, "Nursery");
		AlienAge.CommonSettings.Classes.LoadComboWithClasses(cboPreprimaryClass_2, "Nursery");
		WorkingSemesters.GetYears(comboBoxEdit10);
		comboBoxEdit9.SelectedItem = WorkingSemesters.GetWorkingSemester();
		spinAcademicYear.Value = DateTime.Now.Year;
		comboBoxEdit11.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboTerm.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboRptTerm.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboSemesterStatic.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboSemesterStaticA.SelectedItem = WorkingSemesters.GetWorkingSemester();
		cboAnalysisSemester.SelectedItem = WorkingSemesters.GetWorkingSemester();
		WorkingSemesters.GetYears(repositoryItemComboBox2);
		WorkingSemesters.GetYears(repositoryItemComboBox1);
		WorkingSemesters.GetSemesters(repositoryItemComboBox3);
		AlienAge.ReportHeaders.ReportHeader.InitializeReportHeader();
		base.WindowState = FormWindowState.Maximized;
		RegistryKey registryKey = Registry.CurrentUser.CreateSubKey("Software\\Alien Age\\School Management Dynamics\\Skins");
		try
		{
			defaultLookAndFeel1.LookAndFeel.SkinName = registryKey.GetValue("defaultSkin").ToString();
		}
		catch
		{
			defaultLookAndFeel1.LookAndFeel.SkinName = "Office 2013";
		}
		DateTime now = DateTime.Now;
		Budget.PopulateBudgetGallery(new GalleryDropDown[1] { galleryBudgetReview });
		Payroll.PopulatePayrollGallery(new GalleryDropDown[1] { galleryPayroll });
		ExtractYearsFromSemester();
		SplashScreenManager.CloseForm(throwExceptionIfAlreadyClosed: false);
	}

	private void ExtractYearsFromSemester()
	{
		string workingSemester = WorkingSemesters.GetWorkingSemester();
		if (!string.IsNullOrEmpty(workingSemester))
		{
			int result = (int.TryParse(workingSemester.Substring(workingSemester.Length - 4, 4), out result) ? result : DateTime.Now.Year);
			for (int i = result - 1; i < result + 3; i++)
			{
				cboAnnualYear.Properties.Items.Add(i.ToString());
			}
		}
	}

	private void GetTenYearsBack()
	{
		int year = DateTime.Now.Year;
		for (int num = year; num > year - 11; num--)
		{
			cboYearScoreboard.Properties.Items.Add(num.ToString());
		}
	}

	private void DisAblePrintButtons()
	{
		barButtonItem271.Enabled = false;
		barButtonItem270.Enabled = false;
		barButtonItem103.Enabled = false;
	}

