	private void UpdateClassGroup(CloseUpEventArgs e)
	{
		try
		{
			SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			sqlConnection.Open();
			SqlCommand sqlCommand = new SqlCommand
			{
				Connection = sqlConnection,
				CommandText = "UPDATE Classes SET ClassGroup=@ClassGroup,SubGroup=@SubGroup WHERE ClassId=@ClassId",
				CommandType = CommandType.Text
			};
			SqlParameter sqlParameter = sqlCommand.Parameters.Add("@ClassGroup", SqlDbType.VarChar, 15);
			sqlParameter.Value = e.Value.ToString();
			sqlParameter.Direction = ParameterDirection.Input;
			sqlParameter = sqlCommand.Parameters.Add("@SubGroup", SqlDbType.VarChar, 15);
			sqlParameter.Value = gridView7.GetRowCellValue(gridView7.GetFocusedDataSourceRowIndex(), "SubGroup");
			sqlParameter.Direction = ParameterDirection.Input;
			sqlParameter = sqlCommand.Parameters.Add("@ClassId", SqlDbType.VarChar, 8);
			sqlParameter.Value = gridView7.GetRowCellValue(gridView7.GetFocusedDataSourceRowIndex(), "ClassId");
			sqlParameter.Direction = ParameterDirection.Input;
			if (sqlCommand.ExecuteNonQuery() > 0)
			{
				GetClassesForModify();
				AlienAge.CommonSettings.Classes.LoadComboWithClasses(cboPreprimaryClass, "Nursery");
				AlienAge.CommonSettings.Classes.LoadComboWithClasses(cboPreprimaryClass_2, "Nursery");
			}
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
	}

	private void UpdateSubGroup(CloseUpEventArgs e)
	{
		try
		{
			SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase());
