			SqlCommand sqlCommand = new SqlCommand
			{
				Connection = sqlConnection,
				CommandText = "UPDATE Classes SET ClassGroup=@ClassGroup,SubGroup=@SubGroup WHERE ClassId=@ClassId",
				CommandType = CommandType.Text
			};
			SqlParameter sqlParameter = sqlCommand.Parameters.Add("@ClassGroup", SqlDbType.VarChar, 15);
			sqlParameter.Value = gridView7.GetRowCellValue(gridView7.GetFocusedDataSourceRowIndex(), "ClassGroup");
			sqlParameter.Direction = ParameterDirection.Input;
			sqlParameter = sqlCommand.Parameters.Add("@SubGroup", SqlDbType.VarChar, 15);
			sqlParameter.Value = e.Value;
			sqlParameter.Direction = ParameterDirection.Input;
			sqlParameter = sqlCommand.Parameters.Add("@ClassId", SqlDbType.VarChar, 8);
			sqlParameter.Value = gridView7.GetRowCellValue(gridView7.GetFocusedDataSourceRowIndex(), "ClassId");
			sqlParameter.Direction = ParameterDirection.Input;
			if (sqlCommand.ExecuteNonQuery() > 0)
			{
				GetClassesForModify();
