	private void GetClassesForModify()
	{
		try
		{
			using SqlDataAdapter sqlDataAdapter = new SqlDataAdapter("SELECT * FROM Classes WHERE SubGroup <> '----' Order By Id", DataConnection.ConnectToDatabase());
			using DataSet dataSet = new DataSet();
			sqlDataAdapter.Fill(dataSet, "ClassesList");
			c_dt = new DataTable();
			c_dt = dataSet.Tables[0];
			gridControl2.DataSource = c_dt.DefaultView;
			LoadClassgroups();
			LoadClassSubgroups();
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
	}

	private void LoadHouses(ComboBoxEdit myCombo)
	{
		try
		{
			using SqlConnection selectConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			SqlDataAdapter sqlDataAdapter = new SqlDataAdapter("Select * from Houses", selectConnection);
			dataSet = new DataSet();
			sqlDataAdapter.Fill(dataSet, "Hall");
			dataTable = dataSet.Tables[0];
			myCombo.Properties.Items.Clear();
			if (dataTable.Rows.Count == 0)
			{
				myCombo.Properties.Items.Clear();
				myCombo.Properties.Items.Add("-");
				myCombo.SelectedIndex = 0;
				return;
			}
			myCombo.Properties.Items.Clear();
			foreach (DataRow row in dataTable.Rows)
			{
				myCombo.Properties.Items.Add(row["HouseName"]);
			}
			myCombo.SelectedIndex = 0;
		}
		catch
		{
		}
	}

	private void LoadStudentIDS(string viewType, string _class, string stream, string templateType)
	{
		if (viewType == "FullPage")
		{
			using (I_Xtreme.StudentIDs.S_1_IDS s_1_IDS = new I_Xtreme.StudentIDs.S_1_IDS())
			{
				s_1_IDS.PaperKind = DXPaperKind.A4;
				s_1_IDS.Detail1.PageBreak = PageBreak.None;
				s_1_IDS.Margins.Bottom = 20f;
				s_1_IDS.Margins.Top = 20f;
				s_1_IDS.Margins.Left = 20f;
				s_1_IDS.Margins.Right = 20f;
				s_1_IDS.Detail1.MultiColumn.ColumnCount = 2;
				s_1_IDS.Detail1.MultiColumn.ColumnSpacing = 100f;
				s_1_IDS.Detail1.MultiColumn.ColumnWidth = 339f;
				s_1_IDS.Detail1.MultiColumn.Layout = ColumnLayout.AcrossThenDown;
				s_1_IDS.Detail1.MultiColumn.Mode = MultiColumnMode.UseColumnCount;
				s_1_IDS.Detail1.HeightF = 230f;
				ReportPrintTool reportPrintTool = new ReportPrintTool(s_1_IDS);
				reportPrintTool.PreviewRibbonForm.Ribbon.RibbonStyle = RibbonControlStyle.Office2013;
				reportPrintTool.PreviewRibbonForm.Ribbon.ShowApplicationButton = DefaultBoolean.False;
				reportPrintTool.PreviewRibbonForm.Ribbon.ShowCategoryInCaption = false;
				reportPrintTool.PreviewRibbonForm.Ribbon.ShowPageHeadersMode = ShowPageHeadersMode.Hide;
				reportPrintTool.PreviewRibbonForm.Ribbon.ShowToolbarCustomizeItem = false;
				reportPrintTool.PreviewRibbonForm.Text = $"School Management Dynamics, Students IDS - ({_class} {stream})";
				reportPrintTool.ShowRibbonPreviewDialog();
				return;
			}
		}
		if (!(viewType == "SingleSingle"))
		{
			return;
		}
		if (templateType == "SystemTemplate")
		{
			using (I_Xtreme.StudentIDs.S_1_IDS report = new I_Xtreme.StudentIDs.S_1_IDS())
			{
				ReportPrintTool reportPrintTool2 = new ReportPrintTool(report);
				reportPrintTool2.PreviewRibbonForm.Ribbon.RibbonStyle = RibbonControlStyle.Office2013;
				reportPrintTool2.PreviewRibbonForm.Ribbon.ShowApplicationButton = DefaultBoolean.False;
				reportPrintTool2.PreviewRibbonForm.Ribbon.ShowCategoryInCaption = false;
				reportPrintTool2.PreviewRibbonForm.Ribbon.ShowPageHeadersMode = ShowPageHeadersMode.Hide;
				reportPrintTool2.PreviewRibbonForm.Ribbon.ShowToolbarCustomizeItem = false;
				reportPrintTool2.PreviewRibbonForm.Text = $"School Management Dynamics, Students IDS - ({_class} {stream})";
				reportPrintTool2.ShowRibbonPreviewDialog();
				return;
			}
		}
		if (templateType == "UserTemplate")
		{
			using (I_Xtreme.StudentIDs_Custom.S_1_IDS report2 = new I_Xtreme.StudentIDs_Custom.S_1_IDS())
			{
				ReportPrintTool reportPrintTool3 = new ReportPrintTool(report2);
				reportPrintTool3.PreviewRibbonForm.Ribbon.RibbonStyle = RibbonControlStyle.Office2013;
				reportPrintTool3.PreviewRibbonForm.Ribbon.ShowApplicationButton = DefaultBoolean.False;
				reportPrintTool3.PreviewRibbonForm.Ribbon.ShowCategoryInCaption = false;
				reportPrintTool3.PreviewRibbonForm.Ribbon.ShowPageHeadersMode = ShowPageHeadersMode.Hide;
				reportPrintTool3.PreviewRibbonForm.Ribbon.ShowToolbarCustomizeItem = false;
				reportPrintTool3.PreviewRibbonForm.Text = $"School Management Dynamics, Students IDS - ({_class} {stream})";
				reportPrintTool3.ShowRibbonPreviewDialog();
			}
		}
	}

	private static void LoadStreams(ComboBoxEdit _cboClass, ComboBoxEdit _cboStream)
	{
		try
		{
			using SqlConnection selectConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			string selectCommandText = $"SELECT * FROM Streams WHERE ClassId='{_cboClass.SelectedItem}'";
			SqlDataAdapter sqlDataAdapter = new SqlDataAdapter(selectCommandText, selectConnection);
			DataSet dataSet = new DataSet();
			sqlDataAdapter.Fill(dataSet, "Streams");
			DataTable dataTable = new DataTable();
			dataTable = dataSet.Tables[0];
			if (dataTable.Rows.Count == 0)
			{
				_cboStream.Properties.Items.Clear();
				_cboStream.Properties.Items.Add("-");
				_cboStream.SelectedIndex = 0;
				return;
			}
			_cboStream.Properties.Items.Clear();
			foreach (DataRow row in dataTable.Rows)
			{
				_cboStream.Properties.Items.Add(row["StreamId"]);
			}
			_cboStream.SelectedIndex = 0;
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics");
		}
	}

