	private void barButtonItem16_ItemClick(object sender, ItemClickEventArgs e)
	{
		SqlDataAdapter sqlDataAdapter = new SqlDataAdapter("SELECT * FROM SchoolDetails WHERE T_T IS NULL OR T_T=''", DataConnection.ConnectToDatabase());
		DataTable dataTable = new DataTable();
		sqlDataAdapter.Fill(dataTable);
		if (dataTable.Rows.Count > 0)
		{
			XtraMessageBox.Show("Please set StudentID number prefix first", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
			return;
		}
		if (LicenceStatus.IsTrialExpired)
		{
			XtraMessageBox.Show("Either your license has expired or you have not registered your application.\nPlease register your application", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
			return;
		}
		using editStudents editStudents2 = new editStudents(EditMode: false);
		editStudents2.Text = "Add New Student";
		if (SchoolInfoTemp.UseDashboard)
		{
			editStudents2.txtUniqueGuid.Text = Guid.NewGuid().ToString();
			editStudents2.cboNationality.SelectedIndex = 50;
			editStudents2.admissionYear = DateTime.Now.Year.ToString();
			editStudents2.cboStatus.SelectedIndex = 0;
			editStudents2.ShowDialog();
		}
		else
		{
			_usrStudentList = new usrStudentList("No Class");
			editStudents2.txtUniqueGuid.Text = Guid.NewGuid().ToString();
			editStudents2.cboNationality.SelectedIndex = 50;
			editStudents2.admissionYear = DateTime.Now.Year.ToString();
			editStudents2.cboStatus.SelectedIndex = 0;
			editStudents2.StartTimer = _usrStudentList.StudentCallBackFN;
			editStudents2.ShowDialog();
		}
	}

