	private void LoadUnclosedOrders()
	{
		try
		{
			using SqlConnection selectConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			using SqlDataAdapter sqlDataAdapter = new SqlDataAdapter("SELECT InvoiceNo, supplier AS Supplier FROM tbl_InvoiceNumbers", selectConnection);
			using DataSet dataSet = new DataSet();
			sqlDataAdapter.Fill(dataSet, "AllOrders");
			DataTable dataTable = new DataTable();
			dataTable = dataSet.Tables[0];
			repositoryItemLookUpEdit1.Columns.Clear();
			repositoryItemLookUpEdit1.DataSource = dataTable;
			repositoryItemLookUpEdit1.ValueMember = "InvoiceNo";
			repositoryItemLookUpEdit1.DisplayMember = "Supplier";
			LookUpColumnInfoCollection columns = repositoryItemLookUpEdit1.Columns;
			columns.Add(new LookUpColumnInfo("InvoiceNo", 0));
			columns.Add(new LookUpColumnInfo("Supplier", 0));
			repositoryItemLookUpEdit1.BestFitMode = BestFitMode.BestFitResizePopup;
			repositoryItemLookUpEdit1.SearchMode = SearchMode.AutoComplete;
			repositoryItemLookUpEdit1.AutoSearchColumnIndex = 0;
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
	}

