		{
			waitDialogForm.SetCaption("Client Email Application is loading");
			string empty = string.Empty;
			empty = ((!(SupplierOptions.ActiveSupplierEmail() == string.Empty)) ? SupplierOptions.ActiveSupplierEmail() : "supplieremail@domain.com");
			Process.Start($"mailto:{empty}?subject={AlienAge.ReportHeaders.ReportHeader.SchoolName}");
