	private void ribbon_SelectedPageChanged(object sender, EventArgs e)
	{
		if (ribbon.SelectedPage == ribbonStudents)
		{
			if (SchoolInfoTemp.UseDashboard)
			{
				barButtonItem17.Visibility = BarItemVisibility.Never;
				usrStudentActivator = new usrStudentActivator();
				CurrentControl.LoadControl(usrStudentActivator, panelMain);
			}
			else
			{
				barButtonItem17.Visibility = BarItemVisibility.Always;
				_usrStudentList = new usrStudentList("No Class");
				_usrStudentList.StatusMessage = StatusMessageCallBackFN;
				CurrentControl.LoadControl(_usrStudentList, panelMain);
			}
			lblAccountAction.Caption = "Students";
			HidePageCategories();
		}
		else if (ribbon.SelectedPage == ribbonEmployees)
		{
			_usrEmployeeList = new usrEmployeeList();
			CurrentControl.LoadControl(_usrEmployeeList, panelMain);
			lblAccountAction.Caption = "Employees";
			HidePageCategories();
			DisAbleEnableStudentButtons(buttonStatus: true);
		}
		else if (ribbon.SelectedPage == ribbonSuppliers)
		{
			_usrSupplierList = new usrSupplierList();
			CurrentControl.LoadControl(_usrSupplierList, panelMain);
			lblAccountAction.Caption = "Supliers";
			HidePageCategories();
			DisAbleEnableStudentButtons(buttonStatus: true);
		}
		else if (ribbon.SelectedPage == ribbonAcademics)
		{
			_usrAcademicsDashBoard = new usrAcademicsDashBoard();
			CurrentControl.LoadControl(_usrAcademicsDashBoard, panelMain);
			lblAccountAction.Caption = "Academics";
			HidePageCategories();
			DisAbleEnableStudentButtons(buttonStatus: true);
		}
		else if (ribbon.SelectedPage == ribbonAccounts)
		{
			_usrAccoutsDashBoard = new usrAccoutsDashBoard();
			CurrentControl.LoadControl(_usrAccoutsDashBoard, panelMain);
			lblAccountAction.Caption = "Accounts";
			HidePageCategories();
			DisAbleEnableStudentButtons(buttonStatus: true);
		}
		else if (ribbon.SelectedPage == ribbonWelcome)
		{
			_usrMainDashBoard = new usrMainDashBoard();
			CurrentControl.LoadControl(_usrMainDashBoard, panelMain);
			lblAccountAction.Caption = "Welcome";
			HidePageCategories();
			DisAbleEnableStudentButtons(buttonStatus: true);
		}
		else if (ribbon.SelectedPage == ribbonInventory)
		{
			_usrStockItems = new usrStockItems();
			CurrentControl.LoadControl(_usrStockItems, panelMain);
			lblAccountAction.Caption = "Inventory";
			ribbonPageCatInventory.Visible = true;
			ribbonPageCatPrePriSubjects.Visible = false;
			DisAbleEnableStudentButtons(buttonStatus: true);
		}
