	private void KeyAssignments(KeyEventArgs e)
	{
		if (e.KeyCode == Keys.I && e.Control && e.Shift)
		{
			StudentImport studentImport = new StudentImport();
			studentImport.ShowDialog();
			return;
		}
		if (e.KeyCode == Keys.L && e.Control)
		{
			lblCurrentUser.Caption = "Not Set";
			ribbon.SelectedPage = ribbonWelcome;
			ribbonPageStudentAccounts.Visible = false;
			ribbonPageFeesFollowUp.Visible = ribbonPageStudentAccounts.Visible;
			ribbonPageSchoolAccounts.Visible = false;
			ribbonPageMarkSheets.Visible = false;
			ribbonStudentAccounts.Visible = false;
			ribbonSchoolAccounts.Visible = false;
			ribbonPageOLevelMarkSheet.Visible = false;
			using Login login = new Login();
			login.ShowDialog();
			return;
		}
		if (e.KeyCode == Keys.C && e.Control && e.Shift)
		{
			using (ConnectToDatabase connectToDatabase = new ConnectToDatabase())
			{
				connectToDatabase.ShowDialog();
				return;
			}
		}
		if (e.KeyCode == Keys.F1)
		{
			try
			{
				Process.Start(Application.StartupPath + "//Help//IR_Help.chm");
				return;
			}
			catch (Exception ex)
			{
				XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
				return;
			}
		}
		if (e.KeyCode == Keys.I && e.Control && e.Shift)
		{
			CustomIdMaker customIdMaker = new CustomIdMaker();
			customIdMaker.ShowDialog();
		}
		else if (e.KeyCode == Keys.O && ribbon.SelectedPage == ribbonAccounts)
		{
			OldStudentsPayment oldStudentsPayment = new OldStudentsPayment();
			oldStudentsPayment.ShowDialog();
		}
		else if (e.KeyCode == Keys.J && ribbon.SelectedPage == ribbonAccounts)
		{
			NormalizeLedgers normalizeLedgers = new NormalizeLedgers("Normal", "");
			normalizeLedgers.ShowDialog();
		}
		else if (e.KeyCode == Keys.N && e.Control && e.Shift)
		{
			NormalizeNumbers normalizeNumbers = new NormalizeNumbers();
			normalizeNumbers.ShowDialog();
		}
	}

