	private void LoadStreamsList()
	{
		try
		{
			using SqlConnection selectConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			SqlDataAdapter sqlDataAdapter = new SqlDataAdapter("Select * from Classes", selectConnection);
			DataSet dataSet = new DataSet();
			sqlDataAdapter.Fill(dataSet, "Classes");
			DataTable dataTable = new DataTable();
			dataTable = dataSet.Tables[0];
			cboClassStream.Properties.Items.Clear();
			foreach (DataRow row in dataTable.Rows)
			{
				cboClassStream.Properties.Items.Add(row["ClassId"]);
			}
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
	}

	private void PopulateGridWithStreams()
