	private void simpleButton44_Click(object sender, EventArgs e)
	{
		if (cboClassStream.EditValue == null || txtStream.Text == string.Empty)
		{
			XtraMessageBox.Show("One of the required fields is empty:\n-Select a class from the dropdown list.\n-Add all the streams you have that correspond to the selected class.", "Warning");
			return;
		}
		try
		{
			using SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			sqlConnection.Open();
			using SqlCommand sqlCommand = new SqlCommand
			{
				Connection = sqlConnection,
				CommandText = $"SELECT * FROM Streams WHERE StreamId='{txtStream}' AND ClassId='{cboClassStream.SelectedItem}'",
				CommandType = CommandType.Text
			};
			SqlDataReader sqlDataReader = sqlCommand.ExecuteReader();
			if (sqlDataReader.HasRows)
			{
				XtraMessageBox.Show("The Stream you are adding is already assigned to the selected class", "Duplicate Entries");
				sqlConnection.Close();
				return;
			}
			sqlConnection.Close();
			using (SqlConnection sqlConnection2 = new SqlConnection(DataConnection.ConnectToDatabase()))
			{
				sqlConnection2.Open();
				using (SqlCommand sqlCommand2 = new SqlCommand
				{
					Connection = sqlConnection2,
					CommandText = "INSERT INTO Streams (StreamId,ClassId,StreamName)VALUES(@StreamId,@ClassId,@StreamName)",
					CommandType = CommandType.Text
				})
				{
					SqlParameter sqlParameter = sqlCommand2.Parameters.Add("@ClassId", SqlDbType.VarChar, 50);
					sqlParameter.Value = cboClassStream.SelectedItem.ToString();
					sqlParameter.Direction = ParameterDirection.Input;
					sqlParameter = sqlCommand2.Parameters.Add("@StreamId", SqlDbType.VarChar, 50);
					sqlParameter.Value = txtStream.Text.Trim();
					sqlParameter.Direction = ParameterDirection.Input;
					sqlParameter = sqlCommand2.Parameters.Add("@StreamName", SqlDbType.VarChar, 50);
					sqlParameter.Value = txtStream.Text.Trim();
					sqlParameter.Direction = ParameterDirection.Input;
					sqlCommand2.ExecuteNonQuery();
				}
				sqlConnection2.Close();
			}
			txtStream.Text = null;
			PopulateGridWithStreams();
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics");
		}
	}

	private void simpleButton33_Click(object sender, EventArgs e)
	{
		try
		{
			if (txtTuitionBoarding.Text == string.Empty && txtDayTuition.Text == string.Empty && cboMyClasses.SelectedIndex == 0)
			{
				XtraMessageBox.Show("One of the fields is empty, fill in all the fields before you can continue", "Warning");
				return;
			}
			simpleButton33.Enabled = false;
			using SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			sqlConnection.Open();
			using (SqlCommand sqlCommand = new SqlCommand
			{
				Connection = sqlConnection,
				CommandText = "UPDATE Classes SET TuitionResidents=@TuitionResidents,TuitionNonResidents=@TuitionNonResidents WHERE ClassId=@ClassId",
				CommandType = CommandType.Text
			})
			{
				SqlParameter sqlParameter = sqlCommand.Parameters.Add("@ClassId", SqlDbType.VarChar, 50);
				sqlParameter.Value = cboMyClasses.SelectedItem;
				sqlParameter.Direction = ParameterDirection.Input;
				sqlParameter = sqlCommand.Parameters.Add("@TuitionResidents", SqlDbType.Money);
				sqlParameter.Value = txtTuitionBoarding.Text.Trim();
				sqlParameter.Direction = ParameterDirection.Input;
				sqlParameter = sqlCommand.Parameters.Add("@TuitionNonResidents", SqlDbType.Money);
				sqlParameter.Value = txtDayTuition.Text.Trim();
				sqlParameter.Direction = ParameterDirection.Input;
				if (sqlCommand.ExecuteNonQuery() > 0)
				{
					sqlConnection.Close();
					string text = $"The Fees Structure for: {cboMyClasses.SelectedItem} has been changed successfully";
					if (XtraMessageBox.Show(text + "\nDo you want to update fees attached to students also?", "Confirm", MessageBoxButtons.YesNo, MessageBoxIcon.Question) == DialogResult.Yes)
					{
						using SqlConnection sqlConnection2 = new SqlConnection(DataConnection.ConnectToDatabase());
						sqlConnection2.Open();
						myTrans = sqlConnection2.BeginTransaction();
						using (SqlCommand sqlCommand2 = new SqlCommand
						{
							Connection = sqlConnection2,
							Transaction = myTrans,
							CommandText = $"UPDATE tbl_Stud SET RequiredFees='{txtTuitionBoarding.Text.Trim()}' WHERE StudyStatus='B' AND ClassId='{cboMyClasses.SelectedItem}'",
							CommandType = CommandType.Text
						})
						{
							sqlCommand2.ExecuteNonQuery();
						}
						using (SqlCommand sqlCommand3 = new SqlCommand
						{
							Connection = sqlConnection2,
							Transaction = myTrans,
							CommandText = $"UPDATE tbl_Stud SET RequiredFees='{txtDayTuition.Text.Trim()}' WHERE StudyStatus='D' AND ClassId='{cboMyClasses.SelectedItem}'",
							CommandType = CommandType.Text
						})
						{
							sqlCommand3.ExecuteNonQuery();
						}
						myTrans.Commit();
						sqlConnection2.Close();
					}
				}
			}
			CustomDialog.ShowCustomDialog("Fees updated successfully");
			LoadFeesStructure();
			txtDayTuition.Text = null;
			txtTuitionBoarding.Text = null;
			simpleButton33.Enabled = true;
			cboMyClasses.SelectedIndex = 0;
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics");
			simpleButton33.Enabled = true;
		}
	}

	private void backstageViewControl1_SelectedTabChanged(object sender, BackstageViewItemEventArgs e)
	{
		if (backstageViewControl1.SelectedTab == viewStream)
		{
			LoadStreamsList();
			PopulateGridWithStreams();
		}
		else if (backstageViewControl1.SelectedTab == viewFeesStructure)
		{
			LoadFeesStructure();
		}
		else if (backstageViewControl1.SelectedTab == viewSchoolDetails)
		{
			UploadDetails();
		}
		else if (backstageViewControl1.SelectedTab == viewMiscellaneous)
		{
			cboNumberOfCopies.SelectedItem = Receipt.NumberOfCopies.ToString();
			txtReceiptPrinter.Text = Receipt.ReceiptPrinter.ToString();
			chkPrintReceipt.Checked = Receipt.AlwaysPrintReceipt;
			txtReceiptPrinter.Text = Receipt.ReceiptPrinter;
			checkEdit2.Checked = FinalAccounts.CannotShowDialog;
		}
		else if (backstageViewControl1.SelectedTab == viewSecurity)
		{
			LoadUserLists();
		}
		else if (backstageViewControl1.SelectedTab == viewReportSettings)
		{
			printControl11 = new PrintControl();
			panelControl33.Controls.Add(printControl11);
			printControl11.Dock = DockStyle.Fill;
			_template = new ReportTemplate();
			_template.ShowPrintStatusDialog = false;
			printControl11.PrintingSystem = _template.PrintingSystem;
			_template.CreateDocument();
		}
	}

