	private void UploadDetails()
	{
		try
		{
			using SqlConnection selectConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			SqlDataAdapter sqlDataAdapter = new SqlDataAdapter("SELECT * FROM SchoolDetails", selectConnection);
			DataSet dataSet = new DataSet();
			sqlDataAdapter.Fill(dataSet, "School_Details");
			DataTable dataTable = new DataTable();
			dataTable = dataSet.Tables[0];
			foreach (DataRow row in dataTable.Rows)
			{
				txtSchoolName.Text = AlienAge.Security.CryptorEngine.Decrypt(row["SchoolName"].ToString());
				txtschoolmotto1.Text = row["schoolMotto"].ToString();
				txtBoxNumber1.Text = row["boxNumber"].ToString();
				txtDistrict.Text = row["district"].ToString();
				txtBlock.Text = AlienAge.Security.CryptorEngine.Decrypt(row["location"].ToString());
				txtMobile.Text = AlienAge.Security.CryptorEngine.Decrypt(row["mobileContact"].ToString());
				txtOffice.Text = row["officeContact"].ToString();
				txtemailAddress1.Text = row["emailAddress"].ToString();
				txtWeb.Text = row["webAddress"].ToString();
				txtName2.Text = row["ShortName"].ToString();
				txtNoPrefix.Text = row["T_T"].ToString();
				bool result = bool.TryParse(row["SendSMS"].ToString(), out result) && result;
				bool result2 = bool.TryParse(row["UseDashBoard"].ToString(), out result2) && result2;
				SchoolInfoTemp.SendSMS = result;
				SchoolInfoTemp.UseDashboard = result2;
				checkEdit4.Checked = result2;
				checkEdit5.Checked = result;
				int result3 = (int.TryParse(row["NumberDisplay"].ToString(), out result3) ? result3 : 0);
				radioGroup6.SelectedIndex = result3;
				byte[] array = new byte[0];
				array = (byte[])row["logo"];
				using MemoryStream memoryStream = new MemoryStream(array);
				pictureBoxLogo.Image = Image.FromStream(memoryStream);
			}
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message);
		}
	}

