	private void simpleButton73_Click(object sender, EventArgs e)
	{
		if ((comboBoxEdit5.EditValue != null && txtUserName.Text != string.Empty && txtPwd.Text != string.Empty) || txtFullName.Text != string.Empty)
		{
			if (txtPwd.Text == txtPwd2.Text)
			{
				try
				{
					using SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase());
					sqlConnection.Open();
					SqlCommand sqlCommand = new SqlCommand
					{
						Connection = sqlConnection,
						CommandText = "SELECT * FROM tbl_userLogin WHERE userName=@userName",
						CommandType = CommandType.Text
					};
					SqlParameter sqlParameter = sqlCommand.Parameters.Add("@userName", SqlDbType.VarChar, 50);
					sqlParameter.Value = txtUserName.Text.ToLower();
					sqlParameter.Direction = ParameterDirection.Input;
					SqlDataReader sqlDataReader = sqlCommand.ExecuteReader();
					if (!sqlDataReader.HasRows)
					{
						sqlDataReader.Close();
						using SqlCommand sqlCommand2 = new SqlCommand
						{
							Connection = sqlConnection,
							CommandText = "INSERT INTO tbl_userLogin (Name,GroupName,userName,Password,ReadOnly,Bill,Receive,Edit,sAdd,sEdit,eDelete)VALUES(@Name,@GroupName,@userName,@Password,@ReadOnly,@Bill,@Receive,@Edit,@sAdd,@sEdit,@eDelete)",
							CommandType = CommandType.Text
						};
						SqlParameter sqlParameter2 = sqlCommand2.Parameters.Add("@Name", SqlDbType.VarChar, 50);
						sqlParameter2.Value = Thread.CurrentThread.CurrentCulture.TextInfo.ToTitleCase(txtFullName.Text);
						sqlParameter2.Direction = ParameterDirection.Input;
						sqlParameter2 = sqlCommand2.Parameters.Add("@GroupName", SqlDbType.VarChar, 50);
						sqlParameter2.Value = comboBoxEdit5.SelectedItem;
						sqlParameter2.Direction = ParameterDirection.Input;
						sqlParameter2 = sqlCommand2.Parameters.Add("@userName", SqlDbType.VarChar, 50);
						sqlParameter2.Value = txtUserName.Text.ToLower();
						sqlParameter2.Direction = ParameterDirection.Input;
						sqlParameter2 = sqlCommand2.Parameters.Add("@Password", SqlDbType.VarChar, 100);
						sqlParameter2.Value = CryptorEngine.Encrypt(comboBoxEdit5.SelectedItem?.ToString() + txtUserName.Text.ToLower() + txtPwd.Text);
						sqlParameter2.Direction = ParameterDirection.Input;
						sqlParameter2 = sqlCommand2.Parameters.Add("@ReadOnly", SqlDbType.Bit);
						sqlParameter2.Value = false;
						sqlParameter2.Direction = ParameterDirection.Input;
						sqlParameter2 = sqlCommand2.Parameters.Add("@Bill", SqlDbType.Bit);
						sqlParameter2.Value = false;
						sqlParameter2.Direction = ParameterDirection.Input;
						sqlParameter2 = sqlCommand2.Parameters.Add("@Receive", SqlDbType.Bit);
						sqlParameter2.Value = false;
						sqlParameter2.Direction = ParameterDirection.Input;
						sqlParameter2 = sqlCommand2.Parameters.Add("@Edit", SqlDbType.Bit);
						sqlParameter2.Value = false;
						sqlParameter2.Direction = ParameterDirection.Input;
						sqlParameter2 = sqlCommand2.Parameters.Add("@sAdd", SqlDbType.Bit);
						sqlParameter2.Value = true;
						sqlParameter2.Direction = ParameterDirection.Input;
						sqlParameter2 = sqlCommand2.Parameters.Add("@sEdit", SqlDbType.Bit);
						sqlParameter2.Value = true;
						sqlParameter2.Direction = ParameterDirection.Input;
						sqlParameter2 = sqlCommand2.Parameters.Add("@eDelete", SqlDbType.Bit);
						sqlParameter2.Value = true;
						sqlParameter2.Direction = ParameterDirection.Input;
						if (sqlCommand2.ExecuteNonQuery() > 0)
						{
							sqlConnection.Close();
							txtFullName.Text = null;
							txtUserName.Text = null;
							txtPwd.Text = null;
							txtPwd2.Text = null;
							LoadUserLists();
						}
						return;
					}
					sqlDataReader.Close();
					XtraMessageBox.Show("The 'User Name' you provided is already used. Please use another name.", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
					txtUserName.Text = string.Empty;
					return;
				}
				catch (Exception ex)
				{
					XtraMessageBox.Show(ex.Message, "School Management Dynamics");
					return;
				}
			}
			XtraMessageBox.Show("The Passwords don't match", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
		}
		else
		{
			XtraMessageBox.Show("Please input Full Name, User Type, Username and Password", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
		}
	}

	private void LoadUserLists()
	{
		try
		{
			using SqlConnection selectConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			using SqlDataAdapter sqlDataAdapter = new SqlDataAdapter("SELECT * FROM tbl_userLogin", selectConnection);
			ds_users = new DataSet();
			sqlDataAdapter.Fill(ds_users, "UserLogins");
			dt_users = new DataTable();
			dt_users = ds_users.Tables[0];
			gridUserAccounts.DataSource = dt_users.DefaultView;
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics");
		}
	}

