	private void ExportReportToExcel(GridControl gridControl, string _fileName)
	{
		using SaveFileDialog saveFileDialog = new SaveFileDialog
		{
			Title = "Save to",
			FileName = string.Format("{0}_{1}", _fileName, DateTime.Now.ToString("HHMMss")),
			RestoreDirectory = true,
			Filter = "Excel Workbook (*.Xlsx)|*.Xlsx"
		};
		if (saveFileDialog.ShowDialog() == DialogResult.OK)
		{
			printableComponentLink1.Component = gridControl;
			printableComponentLink1.Landscape = false;
			printableComponentLink1.PrintingSystem.ClearContent();
			ReportHeader(_fileName);
			printableComponentLink1.ExportToXlsx(saveFileDialog.FileName);
			if (XtraMessageBox.Show("Do you want to open the file?", "Confirm", MessageBoxButtons.YesNo, MessageBoxIcon.Question) == DialogResult.Yes)
			{
				Process.Start(saveFileDialog.FileName);
			}
		}
	}

	private void ExportReportToExcel(PivotGridControl pivotGrid, string _fileName)
	{
		using SaveFileDialog saveFileDialog = new SaveFileDialog
		{
			Title = "Save to",
			FileName = string.Format("{0}_{1}", _fileName, DateTime.Now.ToString("HHMMss")),
			RestoreDirectory = true,
			Filter = "Excel Workbook (*.Xlsx)|*.Xlsx"
		};
		if (saveFileDialog.ShowDialog() == DialogResult.OK)
		{
			printableComponentLink1.Component = pivotGrid;
			printableComponentLink1.Landscape = false;
			printableComponentLink1.PrintingSystem.ClearContent();
			ReportHeader(_fileName);
			printableComponentLink1.ExportToXlsx(saveFileDialog.FileName);
			if (XtraMessageBox.Show("Do you want to open the file?", "Confirm", MessageBoxButtons.YesNo, MessageBoxIcon.Question) == DialogResult.Yes)
			{
				Process.Start(saveFileDialog.FileName);
			}
		}
	}

	private void barButtonItem176_ItemClick(object sender, ItemClickEventArgs e)
	{
		if (lblStatementType.Text == "pageIncome")
		{
			PrintableControl.ExportControl("Total Revenue", string.Format("From {0} to {1}", dtFromSA.DateTime.ToString("dd-MM-yyyy"), dtEndSA.DateTime.ToString("dd-MM-yyyy")), printableComponentLink1, PrintableControl.PrintableGridControl);
		}
		else if (lblStatementType.Text == "pageExpenses")
		{
			PrintableControl.ExportControl("Total Expenditure", string.Format("From {0} to {1}", dtFromSA.DateTime.ToString("dd-MM-yyyy"), dtEndSA.DateTime.ToString("dd-MM-yyyy")), printableComponentLink1, PrintableControl.PrintablePivotGridControl);
		}
		else if (lblStatementType.Text == "pageExpensesGrouped")
		{
			PrintableControl.ExportControl("Total Expenditure", string.Format("From {0} to {1}", dtFromSA.DateTime.ToString("dd-MM-yyyy"), dtEndSA.DateTime.ToString("dd-MM-yyyy")), printableComponentLink1, PrintableControl.PrintableGridControl);
		}
		else if (lblStatementType.Text == "pageTrialBalance")
		{
			PrintableControl.ExportControl("Total Expenditure", string.Format("From {0} to {1}", dtFromSA.DateTime.ToString("dd-MM-yyyy"), dtEndSA.DateTime.ToString("dd-MM-yyyy")), printableComponentLink1, PrintableControl.PrintableGridControl);
		}
		else if (lblStatementType.Text == "pageIncomeStatement")
		{
			PrintableControl.ExportControl("Income Statement", string.Format("From {0} to {1}", dtFromSA.DateTime.ToString("dd-MM-yyyy"), dtEndSA.DateTime.ToString("dd-MM-yyyy")), printableComponentLink1, PrintableControl.PrintableGridControl);
		}
		else if (lblStatementType.Text == "pageBalanceSheet")
		{
			PrintableControl.ExportControl("Balance Sheet", string.Format("From {0} to {1}", dtFromSA.DateTime.ToString("dd-MM-yyyy"), dtEndSA.DateTime.ToString("dd-MM-yyyy")), printableComponentLink1, PrintableControl.PrintablePivotGridControl);
		}
		else if (lblStatementType.Text == "pageCashbook")
		{
			PrintableControl.ExportControl("Cashbook Analysis", string.Format("From {0} to {1}", dtFromSA.DateTime.ToString("dd-MM-yyyy"), dtEndSA.DateTime.ToString("dd-MM-yyyy")), printableComponentLink1, PrintableControl.PrintableGridControl);
		}
		else if (lblStatementType.Text == "pageAccountLedgers")
		{
			PrintableControl.ExportControl($"{cboLedgerAccount.SelectedItem.ToString()} analysis", string.Format("From {0} to {1}", dtLedgerFrom.DateTime.ToString("dd-MM-yyyy"), dtLedgerTo.DateTime.ToString("dd-MM-yyyy")), printableComponentLink1, PrintableControl.PrintableGridControl);
		}
		else
		{
			XtraMessageBox.Show("Nothing to export! Please load a report.", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
		}
	}

	private void barButtonItem175_ItemClick(object sender, ItemClickEventArgs e)
	{
		if (!LicenceStatus.IsTrialExpired)
		{
			if (ActiveFormSelected.CurrentActiveForm.Contains("Bursary"))
			{
				PrintBursaryStudents("export");
			}
			else if (ActiveFormSelected.CurrentActiveForm.Contains("Waiver"))
			{
				ExportReportToExcel(PrintableControl.PrintableGridControl, ActiveFormSelected.CurrentActiveForm);
			}
			else if (ActiveFormSelected.CurrentActiveForm.Contains("Discounts allowed"))
			{
				ExportReportToExcel(PrintableControl.PrintableGridControl, "School's Bursary providers");
			}
			else if (ActiveFormSelected.CurrentActiveForm.Contains("Graphical summary"))
			{
				PrintBursaryStudents("export");
			}
			else if (ActiveFormSelected.CurrentActiveForm.Contains("Collection Analysis"))
			{
				PrintFeesCollectionAnalysis("export");
			}
			else if (ActiveFormSelected.CurrentActiveForm.Contains("Tracking Sheet"))
			{
				ExportReportToExcel(PrintableControl.PrintableGridControl, ActiveFormSelected.CurrentActiveForm);
			}
			else if (ActiveFormSelected.CurrentActiveForm.Contains("Fees Payment Modes Analysis"))
			{
				ExportReportToExcel(PrintableControl.PrintablePivotGridControl, ActiveFormSelected.CurrentActiveForm);
			}
			else if (ActiveFormSelected.CurrentActiveForm.Contains("Fees Billing Analysis") || ActiveFormSelected.CurrentActiveForm.Contains("Fees Payment Analysis"))
			{
				ExportReportToExcel(PrintableControl.PrintablePivotGridControl, ActiveFormSelected.CurrentActiveForm);
			}
			else if (ActiveFormSelected.CurrentActiveForm.Contains("Fees Arrears Recovery"))
			{
				ExportReportToExcel(PrintableControl.PrintablePivotGridControl, ActiveFormSelected.CurrentActiveForm);
			}
			else if (ActiveFormSelected.CurrentActiveForm.Contains("Fees Arrears Recovery"))
			{
				ExportReportToExcel(PrintableControl.PrintableGridControl, ActiveFormSelected.CurrentActiveForm);
			}
		}
		else
		{
			XtraMessageBox.Show("Sorry! You cannot export because your license expired.\nPlease renew your license in order to export.", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
		}
	}

