	private void simpleButton76_Click(object sender, EventArgs e)
	{
		try
		{
			if (gridView4.GetFocusedDataSourceRowIndex() > -1)
			{
				DialogResult dialogResult = XtraMessageBox.Show("Are you sure you want to delete this stream?", "Confirm", MessageBoxButtons.YesNo, MessageBoxIcon.Question);
				if (dialogResult != DialogResult.Yes)
				{
					return;
				}
				using SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase());
				sqlConnection.Open();
				using SqlCommand sqlCommand = new SqlCommand
				{
					Connection = sqlConnection,
					CommandText = "DELETE FROM Streams WHERE id=@id",
					CommandType = CommandType.Text
				};
				DataRow dataRow = dataTable_Streams.Rows[gridView4.GetFocusedDataSourceRowIndex()];
				SqlParameter sqlParameter = sqlCommand.Parameters.Add("@id", SqlDbType.Int);
				sqlParameter.Value = dataRow["id"];
				sqlParameter.Direction = ParameterDirection.Input;
				sqlCommand.ExecuteNonQuery();
				sqlConnection.Close();
				PopulateGridWithStreams();
				return;
			}
			XtraMessageBox.Show("Please select a stream from the list", "School Management Dynamics");
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
	}

