	private string ReportHeaderStatistics(CompositeLink compLink, string customHeader)
	{
		string text = string.Empty;
		string text2 = string.Empty;
		string text3 = string.Empty;
		try
		{
			using SqlConnection selectConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			using SqlDataAdapter sqlDataAdapter = new SqlDataAdapter("SELECT SchoolName,fullContact,location FROM SchoolDetails", selectConnection);
			using DataSet dataSet = new DataSet();
			sqlDataAdapter.Fill(dataSet, "header");
			DataTable dataTable = new DataTable();
			dataTable = dataSet.Tables[0];
			foreach (DataRow row in dataTable.Rows)
			{
				text = FingerPrint.SchoolName;
				text2 = row["fullContact"].ToString();
				text3 = FingerPrint.Village;
			}
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
		return compLink.RtfReportHeader = $"{{\\rtf1\\ansi\\ansicpg1252\\deff0\\deflang1033{{\\fonttbl{{\\f0\\fnil\\fcharset0 Tahoma;}}}}\r\n\\viewkind4\\uc1\\pard\\qc\\f0\\fs22 {text}\\par\r\n{text3}\\par\r\n{text2}\\par\r\n\\par\r\n{customHeader}\\par\r\n";
	}

	private void PrintChartsAndStatistics(string printAction)
	{
		if (printAction.ToLower() == "print")
		{
			PrintingSystem printingSystem = new PrintingSystem();
			CompositeLink compositeLink = new CompositeLink
			{
				BreakSpace = 60,
				Margins = new Margins(20, 20, 20, 20),
				Landscape = false
			};
			PrintableComponentLink printableComponentLink = new PrintableComponentLink();
			PrintableComponentLink printableComponentLink2 = new PrintableComponentLink();
			PrintableComponentLink printableComponentLink3 = new PrintableComponentLink();
			printingSystem.ClearContent();
			printingSystem.Links.AddRange(new object[4] { printableComponentLink, printableComponentLink2, printableComponentLink3, compositeLink });
			printableComponentLink.Component = PrintableControl.PrintableChartControl;
			printableComponentLink2.Component = PrintableControl.PrintablePivotGridControl;
			printableComponentLink3.Component = PrintableControl.PrintablePivotGridControl_2;
			compositeLink.PrintingSystem.ClearContent();
			compositeLink.Links.AddRange(new object[3] { printableComponentLink, printableComponentLink2, printableComponentLink3 });
			compositeLink.PrintingSystem = printingSystem;
			ReportHeaderStatistics(compositeLink, string.Empty);
			compositeLink.PrintDlg();
		}
		else if (printAction.ToLower() == "preview")
		{
			PrintingSystem printingSystem2 = new PrintingSystem();
