	private void simpleButton13_Click_1(object sender, EventArgs e)
	{
		try
		{
			if (dtBooksBegin.DateTime < dtBooksEnd.DateTime)
			{
				using (SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase()))
				{
					sqlConnection.Open();
					using SqlCommand sqlCommand = new SqlCommand
					{
						Connection = sqlConnection,
						CommandText = "SELECT * FROM tbl_BookingPeriod WHERE Status='Open'",
						CommandType = CommandType.Text
					};
					SqlDataReader sqlDataReader = sqlCommand.ExecuteReader();
					if (sqlDataReader.HasRows)
					{
						DialogResult dialogResult = XtraMessageBox.Show("There exists a Financial Period which is still open. Do you wish to update the dates for this Financial Period instead?", "School Management Dynamics", MessageBoxButtons.YesNo, MessageBoxIcon.Exclamation);
						if (dialogResult == DialogResult.Yes)
						{
							using (SqlConnection sqlConnection2 = new SqlConnection(DataConnection.ConnectToDatabase()))
							{
								sqlConnection2.Open();
								using SqlCommand sqlCommand2 = new SqlCommand
								{
									Connection = sqlConnection2,
									CommandText = "UPDATE tbl_BookingPeriod SET BeginningDate=@BeginningDate,EndingDate=@EndingDate,BooksPeriod=@BooksPeriod WHERE Status=@Status",
									CommandType = CommandType.Text
								};
								SqlParameter sqlParameter = sqlCommand2.Parameters.Add("@BeginningDate", SqlDbType.DateTime);
								sqlParameter.Value = dtBooksBegin.DateTime.ToShortDateString();
								sqlParameter.Direction = ParameterDirection.Input;
								sqlParameter = sqlCommand2.Parameters.Add("@EndingDate", SqlDbType.DateTime);
								sqlParameter.Value = dtBooksEnd.DateTime.ToShortDateString();
								sqlParameter.Direction = ParameterDirection.Input;
								sqlParameter = sqlCommand2.Parameters.Add("@Status", SqlDbType.VarChar, 6);
								sqlParameter.Value = "Open";
								sqlParameter.Direction = ParameterDirection.Input;
								sqlParameter = sqlCommand2.Parameters.Add("@BooksPeriod", SqlDbType.VarChar, 9);
								sqlParameter.Value = txtFinancialYear.Text.ToUpper();
								sqlParameter.Direction = ParameterDirection.Input;
								sqlCommand2.ExecuteNonQuery();
								sqlConnection2.Close();
								CustomDialog.ShowCustomDialog("Financial Period Updated.");
								return;
							}
						}
						return;
					}
					using SqlConnection sqlConnection3 = new SqlConnection(DataConnection.ConnectToDatabase());
					sqlConnection3.Open();
					using SqlCommand sqlCommand3 = new SqlCommand
					{
						Connection = sqlConnection3,
						CommandText = "INSERT INTO tbl_BookingPeriod (BeginningDate,EndingDate,Status,BooksPeriod) VALUES (@BeginningDate,@EndingDate,@Status,@BooksPeriod)",
						CommandType = CommandType.Text
					};
					SqlParameter sqlParameter2 = sqlCommand3.Parameters.Add("@BeginningDate", SqlDbType.DateTime);
					sqlParameter2.Value = dtBooksBegin.DateTime.ToShortDateString();
					sqlParameter2.Direction = ParameterDirection.Input;
					sqlParameter2 = sqlCommand3.Parameters.Add("@EndingDate", SqlDbType.DateTime);
					sqlParameter2.Value = dtBooksEnd.DateTime.ToShortDateString();
					sqlParameter2.Direction = ParameterDirection.Input;
					sqlParameter2 = sqlCommand3.Parameters.Add("@Status", SqlDbType.VarChar, 6);
					sqlParameter2.Value = "Open";
					sqlParameter2.Direction = ParameterDirection.Input;
					sqlParameter2 = sqlCommand3.Parameters.Add("@BooksPeriod", SqlDbType.VarChar, 9);
					sqlParameter2.Value = txtFinancialYear.Text.ToUpper();
					sqlParameter2.Direction = ParameterDirection.Input;
					sqlCommand3.ExecuteNonQuery();
					sqlConnection3.Close();
					CustomDialog.ShowCustomDialog("Financial Period Set.");
					return;
				}
			}
			XtraMessageBox.Show("Closing Date Cannot be less than Openning Date", "Invalid Selection", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
	}

	private void dtBooksBegin_Closed(object sender, ClosedEventArgs e)
	{
		dtBooksEnd.DateTime = dtBooksBegin.DateTime.AddDays(365 - dtBooksEnd.DateTime.DayOfYear);
		txtFinancialYear.Text = dtBooksBegin.DateTime.Year.ToString();
		if (dtBooksBegin.DateTime.Year == dtBooksEnd.DateTime.Year)
		{
			txtFinancialYear.Text = dtBooksBegin.DateTime.Year.ToString();
		}
		else
		{
			XtraMessageBox.Show("Its recommended that all books be closed on 31st December", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
		}
	}

	private void dtBooksEnd_Closed(object sender, ClosedEventArgs e)
	{
		if (dtBooksBegin.DateTime.Year == dtBooksEnd.DateTime.Year)
		{
			txtFinancialYear.Text = dtBooksBegin.DateTime.Year.ToString();
		}
		else
		{
			txtFinancialYear.Text = dtBooksBegin.DateTime.Year + "/" + dtBooksEnd.DateTime.Year;
		}
	}

	private void cboWorkingSemester_Closed(object sender, ClosedEventArgs e)
	{
		if (cboWorkingSemester.SelectedIndex > -1)
		{
			if (SelectedTerm != cboWorkingSemester.SelectedItem.ToString())
			{
				WorkingSemesters.SetWorkingSemester(cboWorkingSemester.SelectedItem.ToString());
				XtraMessageBox.Show("Term successfully set. The application will restart", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
				Application.Restart();
			}
		}
		else
		{
			XtraMessageBox.Show("Please select a Term", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
		}
	}

