		waitDialogForm.SetCaption("Re-Calculating Taxes...");
		try
		{
			popupControlContainer15.HidePopup();
			DialogResult dialogResult = XtraMessageBox.Show("You are about to re-calculate taxes for " + dtRecalculate.DateTime.ToString("MMMM-yyyy") + ".\nDo you really want to do this?", "Confirm", MessageBoxButtons.YesNo, MessageBoxIcon.Question);
			if (dialogResult == DialogResult.Yes)
			{
				_ = dtRecalculate.DateTime;
				if (true)
				{
					waitDialogForm.Show();
					_usrEmployeeDebts = new usrEmployeeDebts();
					CurrentControl.LoadControl(_usrEmployeeDebts, panelMain);
					waitDialogForm.Hide();
				}
			}
			else
			{
				popupControlContainer15.HidePopup();
				waitDialogForm.Hide();
			}
		}
		catch (Exception ex)
		{
			popupControlContainer15.HidePopup();
			waitDialogForm.Hide();
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
	}

