	private void checkEdit11_CheckedChanged(object sender, EventArgs e)
	{
		try
		{
			using SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			sqlConnection.Open();
			using SqlCommand sqlCommand = new SqlCommand
			{
				Connection = sqlConnection,
				CommandText = "SELECT * FROM tbl_EnforceBudget",
				CommandType = CommandType.Text
			};
			SqlDataReader sqlDataReader = sqlCommand.ExecuteReader();
			if (sqlDataReader.HasRows)
			{
				sqlConnection.Close();
				using SqlConnection sqlConnection2 = new SqlConnection(DataConnection.ConnectToDatabase());
				sqlConnection2.Open();
				using SqlCommand sqlCommand2 = new SqlCommand
				{
					Connection = sqlConnection2,
					CommandText = "UPDATE tbl_EnforceBudget SET IsForced=@IsForced",
					CommandType = CommandType.Text
				};
				SqlParameter sqlParameter = sqlCommand2.Parameters.Add("@IsForced", SqlDbType.BigInt);
				sqlParameter.Value = Convert.ToBoolean(checkEdit11.EditValue);
				sqlParameter.Direction = ParameterDirection.Input;
				sqlCommand2.ExecuteNonQuery();
				return;
			}
			sqlConnection.Close();
			using SqlConnection sqlConnection3 = new SqlConnection(DataConnection.ConnectToDatabase());
			sqlConnection3.Open();
			using SqlCommand sqlCommand3 = new SqlCommand
			{
				Connection = sqlConnection3,
				CommandText = "INSERT INTO tbl_EnforceBudget (IsForced) VALUES (@IsForced)",
				CommandType = CommandType.Text
			};
			SqlParameter sqlParameter2 = sqlCommand3.Parameters.Add("@IsForced", SqlDbType.BigInt);
			sqlParameter2.Value = Convert.ToBoolean(checkEdit11.EditValue);
			sqlParameter2.Direction = ParameterDirection.Input;
			sqlCommand3.ExecuteNonQuery();
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
	}

