	private void LoadTransactingAccount()
	{
		try
		{
			SqlDataAdapter sqlDataAdapter = new SqlDataAdapter("SELECT gas.SubAccoutName,gas.subAccountNo,ga.categoryId AS Category FROM tbl_generalAccounts ga RIGHT OUTER JOIN tbl_generalAccounts_Sub gas ON ga.accNo = gas.accNo WHERE  (ga.categoryId <> 1000) AND (ga.categoryId <> 2000) GROUP BY gas.SubAccoutName,gas.subAccountNo,ga.categoryId", DataConnection.ConnectToDatabase());
			DataSet dataSet = new DataSet();
			sqlDataAdapter.Fill(dataSet, "AccountStandingBalance");
			dtLAccounts = new DataTable();
			dtLAccounts = dataSet.Tables[0];
			cboLedgerAccount.Properties.Items.Clear();
			foreach (DataRow row in dtLAccounts.Rows)
			{
				cboLedgerAccount.Properties.Items.Add(row["SubAccoutName"]);
			}
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
	}

