	private void simpleButton19_Click(object sender, EventArgs e)
	{
		if (cboLedgerAccount.SelectedIndex > -1)
		{
			if (dtLedgerFrom.DateTime <= dtLedgerTo.DateTime)
			{
				DataRow dataRow = dtLAccounts.Rows[cboLedgerAccount.SelectedIndex];
				popupControlContainer29.HidePopup();
				WaitFinancialReports waitFinancialReports = new WaitFinancialReports(dtLedgerFrom.DateTime, dtLedgerTo.DateTime, "pageAccountLedgers", cboLedgerAccount.SelectedItem.ToString(), dataRow["subAccountNo"].ToString(), Convert.ToInt32(labelControl7.Text));
				waitFinancialReports.ReportParameters = _usrFinancialReportsDashBoard.AccountReportFN;
				waitFinancialReports.ShowDialog();
			}
			else
			{
				XtraMessageBox.Show("Starting date cannot be greater than ending date.", "Invalid selection", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
			}
		}
		else
		{
			XtraMessageBox.Show("Please select an account you wish to view", "Invalid selection", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
		}
	}

