	private void simpleButton42_Click(object sender, EventArgs e)
	{
		try
		{
			string text = "TermI- TermII- TermIII-";
			string[] array = text.Split();
			foreach (string text2 in array)
			{
				SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase());
				sqlConnection.Open();
				SqlCommand sqlCommand = new SqlCommand
				{
					Connection = sqlConnection,
					CommandText = "SELECT * FROM tbl_PromoStamps WHERE SemesterId=@SemesterId",
					CommandType = CommandType.Text
				};
				SqlParameter sqlParameter = sqlCommand.Parameters.Add("@SemesterId", SqlDbType.VarChar, 12);
				sqlParameter.Value = text2 + spinAcademicYear.Value;
				sqlParameter.Direction = ParameterDirection.Input;
				SqlDataReader sqlDataReader = sqlCommand.ExecuteReader();
				if (!sqlDataReader.HasRows)
				{
					sqlDataReader.Close();
					SqlCommand sqlCommand2 = new SqlCommand
					{
						Connection = sqlConnection,
						CommandText = "INSERT INTO tbl_PromoStamps (SemesterId) VALUES (@SemesterId)",
						CommandType = CommandType.Text
					};
					SqlParameter sqlParameter2 = sqlCommand2.Parameters.Add("@SemesterId", SqlDbType.VarChar, 12);
					sqlParameter2.Value = text2 + spinAcademicYear.Value;
					sqlParameter2.Direction = ParameterDirection.Input;
					sqlCommand2.ExecuteNonQuery();
					sqlConnection.Close();
				}
				else
				{
					sqlDataReader.Close();
					sqlConnection.Close();
				}
			}
			WorkingSemesters.GetSemesters(new ComboBoxEdit[1] { cboWorkingSemester });
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
	}

