	private void galleryBudgetReview_Gallery_ItemClick(object sender, GalleryItemClickEventArgs e)
	{
		if (_ViewMode == "BudgetCreate")
		{
			barButtonItem197.Enabled = true;
			barButtonItem160.Enabled = true;
			using WaitBudget waitBudget = new WaitBudget("pageBudgetCreate", e.Item.Description, e.Item.Caption);
			waitBudget.BudgetParameters = _usrBudgetReports.BudgetFN;
			if (waitBudget.ShowDialog() == DialogResult.OK)
			{
				_BudgetType = e.Item.Description;
				_BudgetPeriod = e.Item.Caption;
				BudgetHeader = $"{e.Item.Caption}";
			}
			return;
		}
		if (!(_ViewMode == "BudgetCompare"))
		{
			return;
		}
		barButtonItem197.Enabled = false;
		barButtonItem160.Enabled = false;
		using WaitBudget waitBudget2 = new WaitBudget("pageBudgetCompare", e.Item.Description, e.Item.Caption);
		waitBudget2.BudgetParameters = _usrBudgetReports.BudgetFN;
		if (waitBudget2.ShowDialog() == DialogResult.OK)
		{
			_BudgetType = e.Item.Description;
			_BudgetPeriod = e.Item.Caption;
			BudgetHeader = $"{e.Item.Caption}";
		}
	}

