	private void simpleButton26_Click(object sender, EventArgs e)
	{
		if (bandedGridView1.GetFocusedDataSourceRowIndex() > -1)
		{
			if (XtraMessageBox.Show("Do you really want to delete this user account?", "Confirm", MessageBoxButtons.YesNo, MessageBoxIcon.Question) != DialogResult.Yes)
			{
				return;
			}
			using SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			sqlConnection.Open();
			using SqlCommand sqlCommand = new SqlCommand
			{
				Connection = sqlConnection,
				CommandText = "DELETE FROM tbl_userLogin WHERE userId=@userId",
				CommandType = CommandType.Text
			};
			SqlParameter sqlParameter = sqlCommand.Parameters.Add("@userId", SqlDbType.Int);
			sqlParameter.Value = SelectedUserId;
			sqlParameter.Direction = ParameterDirection.Input;
			sqlCommand.ExecuteNonQuery();
			sqlConnection.Close();
			LoadUserLists();
			return;
		}
		XtraMessageBox.Show("Please select a user you want to delete from the list", "School Management Dynamics");
	}

	private void UpateAccountPrivilages(int userId, string col, bool value)
	{
		try
		{
			using SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase());
			sqlConnection.Open();
			using SqlCommand sqlCommand = new SqlCommand
			{
				Connection = sqlConnection,
				CommandText = "UPDATE tbl_userLogin SET " + col + "=@ParameterValue WHERE userId=@userId",
				CommandType = CommandType.Text
			};
			SqlParameter sqlParameter = sqlCommand.Parameters.Add("@userId", SqlDbType.Int);
			sqlParameter.Value = userId;
			sqlParameter.Direction = ParameterDirection.Input;
			sqlParameter = sqlCommand.Parameters.Add("@ParameterValue", SqlDbType.Bit);
			sqlParameter.Value = value;
			sqlParameter.Direction = ParameterDirection.Input;
			if (sqlCommand.ExecuteNonQuery() > 0)
			{
				sqlConnection.Close();
				LoadUserLists();
			}
		}
		catch (Exception ex)
		{
			XtraMessageBox.Show(ex.Message, "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
		}
	}

