	private void barButtonItem322_ItemClick(object sender, ItemClickEventArgs e)
	{
		if (XtraMessageBox.Show($"Do you really want to delete the selected account: {ChartAccounts.AccoutName} ({ChartAccounts.SelectedAccount})?", "Confirm", MessageBoxButtons.YesNo, MessageBoxIcon.Question) != DialogResult.Yes)
		{
			return;
		}
		SqlConnection sqlConnection = new SqlConnection(DataConnection.ConnectToDatabase());
		sqlConnection.Open();
		SqlCommand sqlCommand = new SqlCommand
		{
			CommandText = "SELECT accNo FROM FeesPayment WHERE accNo=@accNo",
			Connection = sqlConnection,
			CommandType = CommandType.Text
		};
		SqlParameter sqlParameter = sqlCommand.Parameters.Add("@accNo", SqlDbType.VarChar, 9);
		sqlParameter.Value = ChartAccounts.SelectedAccount;
		sqlParameter.Direction = ParameterDirection.Input;
		SqlDataReader sqlDataReader = sqlCommand.ExecuteReader();
		if (sqlDataReader.HasRows)
		{
			sqlDataReader.Close();
			XtraMessageBox.Show($"The account you selected cannot be deleted because one or more students have been billed for ({ChartAccounts.AccoutName})", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
			return;
		}
		sqlDataReader.Close();
		SqlCommand sqlCommand2 = new SqlCommand
		{
			CommandText = "SELECT accNo FROM tbl_StatementOfAffairs WHERE accNo=@accNo",
			Connection = sqlConnection,
			CommandType = CommandType.Text
		};
		SqlParameter sqlParameter2 = sqlCommand2.Parameters.Add("@accNo", SqlDbType.VarChar, 9);
		sqlParameter2.Value = ChartAccounts.SelectedAccount;
		sqlParameter2.Direction = ParameterDirection.Input;
		SqlDataReader sqlDataReader2 = sqlCommand2.ExecuteReader();
		if (sqlDataReader2.HasRows)
		{
			sqlDataReader2.Close();
			sqlConnection.Close();
			XtraMessageBox.Show("The account you selected cannot be deleted because it has attached transactions", "School Management Dynamics", MessageBoxButtons.OK, MessageBoxIcon.Hand);
			return;
		}
		sqlDataReader2.Close();
		SqlCommand sqlCommand3 = new SqlCommand
		{
			CommandText = "DELETE FROM tbl_generalAccounts_Sub WHERE subAccountNo=@subAccountNo",
			Connection = sqlConnection,
			CommandType = CommandType.Text
		};
		SqlParameter sqlParameter3 = sqlCommand3.Parameters.Add("@subAccountNo", SqlDbType.VarChar, 9);
		sqlParameter3.Value = ChartAccounts.SelectedAccount;
		sqlParameter3.Direction = ParameterDirection.Input;
		sqlCommand3.ExecuteNonQuery();
		sqlConnection.Close();
		_usrChartOfAccounts = new usrChartOfAccounts();
		CurrentControl.LoadControl(_usrChartOfAccounts, panelMain);
	}

