	private void LoadPaymentModes()
	{
		SqlDataAdapter sqlDataAdapter = new SqlDataAdapter("SELECT g.accNo, g.accName, s.subAccountNo, s.SubAccoutName, g.categoryId FROM tbl_generalAccounts g INNER JOIN tbl_generalAccounts_Sub s ON g.accNo = s.accNo WHERE(g.categoryId = 3000)", DataConnection.ConnectToDatabase());
		DataTable dataTable = new DataTable();
		sqlDataAdapter.Fill(dataTable);
		cboPayMode.Properties.Items.Clear();
		foreach (DataRow row in dataTable.Rows)
		{
			cboPayMode.Properties.Items.Add(row["SubAccoutName"].ToString());
		}
	}

