	private string PreviousTerm(string ThisTerm)
	{
		int num = Convert.ToInt32(ThisTerm.Substring(ThisTerm.IndexOf('-') + 1, 4));
		string result = string.Empty;
		if (ThisTerm.Contains("TermI-"))
		{
			result = "TermIII-" + (num - 1);
		}
		else if (ThisTerm.Contains("TermII-"))
		{
			result = "TermI-" + num;
		}
		else if (ThisTerm.Contains("TermIII-"))
		{
			result = "TermII-" + num;
		}
		return result;
	}

