	private void ConnectToDevice()
	{
		//IL_00b7: Unknown result type (might be due to invalid IL or missing references)
		//IL_00c1: Expected O, but got Unknown
		//IL_00ce: Unknown result type (might be due to invalid IL or missing references)
		//IL_00d8: Expected O, but got Unknown
		//IL_00e5: Unknown result type (might be due to invalid IL or missing references)
		//IL_00ef: Expected O, but got Unknown
		//IL_00fc: Unknown result type (might be due to invalid IL or missing references)
		//IL_0106: Expected O, but got Unknown
		//IL_0113: Unknown result type (might be due to invalid IL or missing references)
		//IL_011d: Expected O, but got Unknown
		while (dxValidationDevice.Validate())
		{
			if (dxValidationDevice.GetInvalidControls().Count == 0)
			{
				bool deviceInMemory = Convert.ToBoolean(checkEdit6.EditValue);
				BiometricDeviceInMemory.SetInMemoryDevice(txtIpAddress.Text, deviceInMemory, Convert.ToInt32(txtDeviceNo.Text), Convert.ToInt32(txtPort.Text));
				if (((IZKEM)BiometricDevice.Device).Connect_Net(txtIpAddress.Text, Convert.ToInt32(txtPort.Text)) && ((IZKEM)BiometricDevice.Device).RegEvent(1, 65535))
				{
					((_IZKEMEvents_Event)BiometricDevice.Device).OnConnected += new _IZKEMEvents_OnConnectedEventHandler(Device_OnConnected);
					((_IZKEMEvents_Event)BiometricDevice.Device).OnDisConnected += new _IZKEMEvents_OnDisConnectedEventHandler(Device_OnDisConnected);
					((_IZKEMEvents_Event)BiometricDevice.Device).OnEnrollFinger += new _IZKEMEvents_OnEnrollFingerEventHandler(Device_OnEnrollFinger);
					((_IZKEMEvents_Event)BiometricDevice.Device).OnFinger += new _IZKEMEvents_OnFingerEventHandler(Device_OnFinger);
					((_IZKEMEvents_Event)BiometricDevice.Device).OnAttTransactionEx += new _IZKEMEvents_OnAttTransactionExEventHandler(Device_OnAttTransactionEx);
				}
				break;
			}
		}
	}

